// src/App.js
import React, { useState } from "react";
import { Routes, Route, Navigate } from "react-router-dom";

import Login from "./Login";
import Home from "./Home";
import Profile from "./Profile";
import Dashboard from "./Dashboard";
import AddNew from "./AddNew";
import Tools from "./Tools";
import ToolsGraph from "./ToolsGraph";
import UploadBills from "./UploadBills";
import History from "./History.jsx";
import TravelHistory from "./TravelHistory";
import TicketHistory from "./TicketHistory";
import BillsHistory from "./BillsHistory";
import AddTravel from "./AddTravel";
import AddTicket from "./AddTicket";
import Settings from "./Settings";

export default function App() {
  const [employee, setEmployee] = useState(null);

  const handleLoginSuccess = (emp) => {
    setEmployee(emp);
  };

  const handleLogout = () => {
    setEmployee(null);
  };

  const requireAuth = (element) =>
    employee ? element : <Navigate to="/" replace />;

  return (
    <Routes>
      {/* Login */}
      <Route
        path="/"
        element={<Login onLoginSuccess={handleLoginSuccess} />}
      />

      {/* Home */}
      <Route
        path="/home"
        element={requireAuth(<Home employee={employee} />)}
      />

      {/* Profile */}
      <Route
        path="/profile"
        element={requireAuth(<Profile employee={employee} />)}
      />

      {/* Dashboard */}
      <Route
        path="/dashboard"
        element={requireAuth(
          <Dashboard employee={employee} onLogout={handleLogout} />
        )}
      />

      {/* Add New */}
      <Route
        path="/addnew"
        element={requireAuth(<AddNew employee={employee} />)}
      />

      {/* Travel Form */}
      <Route
        path="/add/travel"
        element={requireAuth(<AddTravel employee={employee} />)}
      />

      {/* Ticket Form */}
      <Route
        path="/add/ticket"
        element={requireAuth(<AddTicket employee={employee} />)}
      />

      {/* Upload Bills (from Add New) */}
      <Route
        path="/add/upload-bills"
        element={requireAuth(<UploadBills employee={employee} />)}
      />

      {/* History menu */}
      <Route
        path="/history"
        element={requireAuth(<History employee={employee} />)}
      />
      <Route
        path="/travel-history"
        element={requireAuth(<TravelHistory employee={employee} />)}
      />
      <Route
        path="/ticket-history"
        element={requireAuth(<TicketHistory employee={employee} />)}
      />
      <Route
        path="/bills-history"
        element={requireAuth(<BillsHistory employee={employee} />)}
      />

      {/* Tools */}
      <Route
        path="/tools"
        element={requireAuth(<Tools employee={employee} />)}
      />
      <Route
        path="/tools/graph"
        element={requireAuth(<ToolsGraph employee={employee} />)}
      />

      {/* Settings */}
      <Route
        path="/settings"
        element={requireAuth(<Settings employee={employee} />)}
      />

      {/* Fallback */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}
